<?php require "vendor/autoload.php"; $app = require_once "bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $models = []; foreach(glob("app/Models/*.php") as $f) { $models[] = "App\Models\\" . basename($f, ".php"); } foreach($models as $m) { if(!class_exists($m)) continue; $model = new $m; try { $table = $model->getTable(); $columns = Illuminate\Support\Facades\Schema::getColumnListing($table); $unused = []; foreach($columns as $c) { $res = shell_exec("findstr /S /M \"$c\" app\\*"); if(empty(trim($res))) { $unused[] = $c; } } echo $m . " (" . $table . "): " . implode(", ", $unused) . "\n"; } catch(Exception $e) {} }
